import{_ as e,o as t,c as o,a3 as s}from"./chunks/framework.CVjg771q.js";const _=JSON.parse('{"title":"生肖 · 马","description":"午马——刚健热烈，勇往直前","frontmatter":{"pageClass":"dao-changshi-page","aside":false,"title":"生肖 · 马","description":"午马——刚健热烈，勇往直前"},"headers":[],"relativePath":"changshi/shengxiao/ma.md","filePath":"changshi/shengxiao/ma.md","lastUpdated":1779783531000}'),i={name:"changshi/shengxiao/ma.md"};function n(r,a,p,c,h,l){return t(),o("div",null,[...a[0]||(a[0]=[s('<h1 id="午马" tabindex="-1">午马 <a class="header-anchor" href="#午马" aria-label="Permalink to &quot;午马&quot;">​</a></h1><blockquote><p>地支「午」· 午时（11:00–13:00）· 五行属火 · 阴阳为阳</p></blockquote><p>马是六畜之首，身体强壮，勇往直前。午时马习惯站着休息。《周易》中说「乾为马」，把马等同于纯阳的乾。金戈铁马的气势、马革裹尸的悲壮、天马行空的自由，都是对马的赞美。项羽的乌骓马、关羽的赤兔马、唐太宗的六骏马……我们还用「马到成功」形容事情顺利。</p><h2 id="生肖故事-折翅天马的救赎" tabindex="-1">生肖故事：折翅天马的救赎 <a class="header-anchor" href="#生肖故事-折翅天马的救赎" aria-label="Permalink to &quot;生肖故事：折翅天马的救赎&quot;">​</a></h2><p>很久以前，马身上有两个大翅膀，不仅可以在陆地奔驰，还可以在天空翱翔。玉帝对其非常喜爱，封其为殿前御马（天马），建御马苑、命仙官喂最好的食物、特批在天宫随意走动。长此以往，天马越来越骄纵。</p><p>一天，天马竟一路跑到东海龙宫，受到神龟和虾兵蟹将的阻拦。天马一气之下与神龟大打出手，踢死了众多虾兵蟹将。龙王把天马告上天庭，玉帝大怒，下令斩去天马的双翼，并将其压在昆仑山下，300年不许翻身。</p><p>后来，人类始祖要从昆仑山经过，天马大喊：「善良的人类始祖，请救救我吧，我愿与您同去人间，终身为您效力！」人类始祖心软了，砍倒山顶的桃树——轰隆一声巨响，天马纵身一跃便跳了出来。</p><p>天马终于重获自由，为了报恩，它履行承诺踏踏实实地为人类效劳——帮人拉车、驮东西，战时和战士一起征战沙场，屡建战功。后来玉帝选拔十二生肖时，人类始祖推荐了马，玉帝看到天马立功赎罪，批准它进入了十二生肖。</p>',8)])])}const m=e(i,[["render",n]]);export{_ as __pageData,m as default};
